import { createRoot, type Root } from 'react-dom/client';
import React, { createRef } from 'react';
import type { RendererInterface, RendererContext, PlayerEvent } from '@content/player-core';
import { saveProgress } from '@content/player-core';
import { VideoRendererView, type VideoRendererHandle } from './VideoRendererView';

export class VideoRenderer implements RendererInterface {
  readonly hasOwnEndScreen = true;

  private root: Root | null = null;
  private handleRef = createRef<VideoRendererHandle>();
  private handlers = new Map<PlayerEvent, Set<(payload: unknown) => void>>();
  private context: RendererContext | null = null;
  private saveTimer: ReturnType<typeof setInterval> | null = null;

  on(event: PlayerEvent, handler: (payload: unknown) => void): void {
    if (!this.handlers.has(event)) this.handlers.set(event, new Set());
    this.handlers.get(event)!.add(handler);
  }

  removeAllListeners(): void {
    this.handlers.clear();
  }

  async mount(container: HTMLElement, context: RendererContext): Promise<void> {
    this.context = context;
    this.root = createRoot(container);

    this.root.render(
      React.createElement(VideoRendererView, {
        ref: this.handleRef,
        context,
        onReady: () => this.fire('player:ready', {}),
        onStart: () => this.fire('player:start', {}),
        onProgress: (progress: number, positionMs: number, durationMs: number) =>
          this.fire('player:progress', { progress, positionMs, durationMs }),
        onComplete: () => this.fire('player:complete', {}),
        onError: (message: string) => this.fire('player:error', { message }),
      }),
    );

    // Persist video position every 5s
    this.saveTimer = setInterval(() => {
      const posMs = this.handleRef.current?.getCurrentPositionMs();
      if (posMs && posMs > 0 && context.contentId) {
        saveProgress(context.contentId, { positionMs: posMs });
      }
    }, 5000);
  }

  async unmount(): Promise<void> {
    if (this.saveTimer) clearInterval(this.saveTimer);

    const posMs = this.handleRef.current?.getCurrentPositionMs();

    // Unmount synchronously before any async work
    this.root?.unmount();
    this.root = null;

    if (posMs && posMs > 0 && this.context?.contentId) {
      await saveProgress(this.context.contentId, { positionMs: posMs });
    }
  }

  getCurrentPosition(): number {
    return this.handleRef.current?.getCurrentPositionMs() ?? 0;
  }

  seek(position: number | string): void {
    const ms = typeof position === 'string' ? parseFloat(position) : position;
    this.handleRef.current?.seekToMs(ms);
  }

  getCompletionState(): boolean {
    return this.handleRef.current?.getCompletionState() ?? false;
  }

  private fire(event: PlayerEvent, payload: unknown): void {
    this.handlers.get(event)?.forEach((h) => h(payload));
  }
}
