import type { CSSProperties, MouseEvent } from 'react';
import type { ThemeConfig } from '@content/player-core';

interface Props {
  isPlaying: boolean;
  buffering: boolean;
  skipDeltaSec?: number;
  onPlayPause: () => void;
  onSkipBack: () => void;
  onSkipForward: () => void;
  theme?: ThemeConfig;
}

export function CenterOverlay({
  isPlaying,
  buffering,
  skipDeltaSec = 10,
  onPlayPause,
  onSkipBack,
  onSkipForward,
  theme,
}: Props) {
  const accent = theme?.primary ?? '#2980b9';

  // Prevent clicks on buttons from bubbling up to the video area
  // (which would trigger play/pause a second time)
  const stop = (e: MouseEvent) => e.stopPropagation();

  return (
    <div style={overlay}>
      {/* Skip back */}
      <button
        style={circleBtn}
        onClick={(e) => { stop(e); onSkipBack(); }}
        aria-label={`Skip back ${skipDeltaSec} seconds`}
      >
        <SkipBackIcon />
        <span style={skipLabel}>−{skipDeltaSec}s</span>
      </button>

      {/* Play / Pause */}
      <button
        style={{ ...playBtn, borderColor: accent }}
        onClick={(e) => { stop(e); onPlayPause(); }}
        aria-label={isPlaying ? 'Pause' : 'Play'}
      >
        {buffering ? (
          <div style={spinner(accent)} />
        ) : isPlaying ? (
          <PauseIcon />
        ) : (
          <PlayIcon />
        )}
      </button>

      {/* Skip forward */}
      <button
        style={circleBtn}
        onClick={(e) => { stop(e); onSkipForward(); }}
        aria-label={`Skip forward ${skipDeltaSec} seconds`}
      >
        <SkipFwdIcon />
        <span style={skipLabel}>+{skipDeltaSec}s</span>
      </button>
    </div>
  );
}

function PlayIcon() {
  return (
    <svg width="28" height="28" viewBox="0 0 24 24" fill="#fff">
      <path d="M6 4l14 8-14 8V4z" />
    </svg>
  );
}
function PauseIcon() {
  return (
    <svg width="28" height="28" viewBox="0 0 24 24" fill="#fff">
      <rect x="6"  y="4" width="4" height="16" rx="1" />
      <rect x="14" y="4" width="4" height="16" rx="1" />
    </svg>
  );
}
function SkipBackIcon() {
  return (
    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.2"
      strokeLinecap="round" strokeLinejoin="round">
      <path d="M11 19A9 9 0 1 0 5.4 8L3 6" />
      <path d="M3 3v5h5" />
    </svg>
  );
}
function SkipFwdIcon() {
  return (
    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.2"
      strokeLinecap="round" strokeLinejoin="round">
      <path d="M13 19a9 9 0 1 0-3.6-11L21 6" />
      <path d="M21 3v5h-5" />
    </svg>
  );
}

// ── Styles ──────────────────────────────────────────────────────────────────

const overlay: CSSProperties = {
  position: 'absolute',
  inset: 0,
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  gap: 28,
  // Transparent to pointer events so clicks on the black area pass through
  pointerEvents: 'none',
};

const circleBtn: CSSProperties = {
  pointerEvents: 'auto',
  width: 68,
  height: 68,
  borderRadius: '50%',
  background: 'rgba(0,0,0,0.55)',
  border: '2px solid rgba(255,255,255,0.3)',
  color: '#fff',
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  cursor: 'pointer',
  gap: 4,
  backdropFilter: 'blur(6px)',
  WebkitBackdropFilter: 'blur(6px)',
};

const playBtn: CSSProperties = {
  pointerEvents: 'auto',
  width: 78,
  height: 78,
  borderRadius: '50%',
  background: 'rgba(0,0,0,0.6)',
  border: '2.5px solid',
  color: '#fff',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  cursor: 'pointer',
  backdropFilter: 'blur(6px)',
  WebkitBackdropFilter: 'blur(6px)',
};

const skipLabel: CSSProperties = {
  fontSize: 12,
  fontWeight: 700,
  color: '#fff',
  lineHeight: 1,
  letterSpacing: '0.2px',
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
  textShadow: '0 1px 3px rgba(0,0,0,0.8)',
};

const spinner = (color: string): CSSProperties => ({
  width: 24,
  height: 24,
  border: '3px solid rgba(255,255,255,0.2)',
  borderTopColor: color,
  borderRadius: '50%',
  animation: 'spin 0.8s linear infinite',
});
