import type { CSSProperties } from 'react';
import type { ThemeConfig } from '@content/player-core';

interface Props {
  savedPositionSec: number;
  onAccept:  () => void;
  onDecline: () => void;
  theme?:    ThemeConfig;
}

function formatPosition(sec: number): string {
  const m = Math.floor(sec / 60);
  const s = Math.floor(sec) % 60;
  return m > 0 ? `${m}m ${String(s).padStart(2, '0')}s` : `${String(s).padStart(2, '0')}s`;
}

export function ResumePrompt({ savedPositionSec, onAccept, onDecline, theme }: Props) {
  const accent = theme?.primary ?? '#FF0000';

  return (
    <div style={overlay}>
      <div style={card}>
        <h3 style={title}>Resume Watching</h3>
        <p style={msg}>
          You were at <strong>{formatPosition(savedPositionSec)}</strong>.
          Continue from where you left off?
        </p>
        <div style={actions}>
          <button style={resumeBtn(accent)} onClick={onAccept}>
            Resume from {formatPosition(savedPositionSec)}
          </button>
          <button style={startBtn} onClick={onDecline}>
            Start from beginning
          </button>
        </div>
      </div>
    </div>
  );
}

const overlay: CSSProperties = {
  position:       'absolute',
  inset:          0,
  display:        'flex',
  alignItems:     'center',
  justifyContent: 'center',
  background:     'rgba(0,0,0,0.75)',
  zIndex:         40,
};

const card: CSSProperties = {
  background:   '#1e1e2e',
  borderRadius: 14,
  padding:      '32px 40px',
  textAlign:    'center',
  color:        '#fff',
  maxWidth:     360,
  boxShadow:    '0 8px 32px rgba(0,0,0,0.5)',
  fontFamily:   '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
};

const title: CSSProperties = { margin: '0 0 12px', fontSize: 18, fontWeight: 700 };

const msg: CSSProperties = {
  fontSize:    14,
  opacity:     0.8,
  marginBottom: 24,
  lineHeight:  1.6,
};

const actions: CSSProperties = { display: 'flex', flexDirection: 'column', gap: 10 };

const resumeBtn = (accent: string): CSSProperties => ({
  padding:      '10px 20px',
  border:       'none',
  borderRadius: 8,
  background:   accent,
  color:        '#fff',
  cursor:       'pointer',
  fontSize:     14,
  fontWeight:   600,
});

const startBtn: CSSProperties = {
  padding:      '10px 20px',
  border:       'none',
  borderRadius: 8,
  background:   'rgba(255,255,255,0.12)',
  color:        '#fff',
  cursor:       'pointer',
  fontSize:     14,
  fontWeight:   500,
};
