import { type CSSProperties } from 'react';
import type { NavItem } from 'epubjs';

interface Props {
  items: NavItem[];
  isDesktop: boolean;
  isOpen: boolean;
  currentCfi: string;
  onSelect: (href: string) => void;
  onClose: () => void;
  toolbarBg: string;
}

export function TocDrawer({
  items,
  isDesktop,
  isOpen,
  currentCfi,
  onSelect,
  onClose,
  toolbarBg,
}: Props) {
  if (!isDesktop && !isOpen) return null;

  return (
    <>
      {/* Backdrop for mobile/tablet */}
      {!isDesktop && (
        <div style={backdrop} onClick={onClose} aria-hidden />
      )}

      <div style={drawer(isDesktop, toolbarBg)}>
        {/* Header */}
        <div style={drawerHeader(toolbarBg)}>
          <span style={drawerTitle}>Contents</span>
          <button style={closeBtn} onClick={onClose} aria-label="Close contents">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
              <path d="M18 6L6 18M6 6l12 12" stroke="currentColor" strokeWidth="2"
                strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          </button>
        </div>

        {/* TOC list */}
        <div style={tocList}>
          {items.length === 0 && (
            <div style={emptyMsg}>No table of contents available</div>
          )}
          {items.map((item) => (
            <TocItem
              key={item.id}
              item={item}
              currentCfi={currentCfi}
              depth={0}
              onSelect={onSelect}
            />
          ))}
        </div>
      </div>
    </>
  );
}

function TocItem({
  item,
  currentCfi,
  depth,
  onSelect,
}: {
  item: NavItem;
  currentCfi: string;
  depth: number;
  onSelect: (href: string) => void;
}) {
  const isActive = currentCfi.includes(item.href.split('#')[0]);

  return (
    <>
      <button
        style={{
          ...tocItemBtn,
          paddingLeft: 16 + depth * 14,
          background: isActive ? 'rgba(255,255,255,0.1)' : 'none',
          fontWeight: isActive ? 600 : 400,
        }}
        onClick={() => onSelect(item.href)}
        title={item.label}
      >
        <span style={tocItemLabel}>{item.label}</span>
        {isActive && <span style={activeIndicator} />}
      </button>

      {item.subitems?.map((sub) => (
        <TocItem
          key={sub.id}
          item={sub}
          currentCfi={currentCfi}
          depth={depth + 1}
          onSelect={onSelect}
        />
      ))}
    </>
  );
}

// ── Styles ────────────────────────────────────────────────────────────────────

const backdrop: CSSProperties = {
  position: 'absolute',
  inset: 0,
  background: 'rgba(0,0,0,0.45)',
  zIndex: 19,
};

const drawer = (isDesktop: boolean, bg: string): CSSProperties => ({
  position: isDesktop ? 'relative' : 'absolute',
  top: isDesktop ? undefined : 0,
  bottom: isDesktop ? undefined : 0,
  left: isDesktop ? undefined : 0,
  width: isDesktop ? 240 : 280,
  flexShrink: 0,
  background: bg,
  display: 'flex',
  flexDirection: 'column',
  zIndex: 20,
  borderRight: '1px solid rgba(255,255,255,0.08)',
  boxShadow: isDesktop ? 'none' : '4px 0 24px rgba(0,0,0,0.4)',
  overflowY: 'hidden',
});

const drawerHeader = (bg: string): CSSProperties => ({
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  padding: '14px 16px',
  borderBottom: '1px solid rgba(255,255,255,0.06)',
  background: bg,
  flexShrink: 0,
});

const drawerTitle: CSSProperties = {
  color: '#fff',
  fontSize: 14,
  fontWeight: 600,
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
};

const closeBtn: CSSProperties = {
  width: 28,
  height: 28,
  border: 'none',
  borderRadius: 6,
  background: 'rgba(255,255,255,0.08)',
  color: '#fff',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  cursor: 'pointer',
};

const tocList: CSSProperties = {
  flex: 1,
  overflowY: 'auto',
  padding: '8px 0',
};

const tocItemBtn: CSSProperties = {
  width: '100%',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  padding: '9px 16px',
  border: 'none',
  background: 'none',
  color: 'rgba(255,255,255,0.75)',
  fontSize: 13,
  textAlign: 'left',
  cursor: 'pointer',
  transition: 'background 0.12s',
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
};

const tocItemLabel: CSSProperties = {
  flex: 1,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const activeIndicator: CSSProperties = {
  width: 6,
  height: 6,
  borderRadius: 3,
  background: '#2980b9',
  flexShrink: 0,
};

const emptyMsg: CSSProperties = {
  padding: '16px',
  color: 'rgba(255,255,255,0.35)',
  fontSize: 13,
  textAlign: 'center',
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
};
