import { useState, useCallback } from 'react';

const MIN_ZOOM = 0.5;
const MAX_ZOOM = 3.0;
const STEP = 0.25;

export interface UseZoomResult {
  zoom: number;
  zoomIn: () => void;
  zoomOut: () => void;
  fitToWidth: () => void;
  fitToWidthImmediate: (cw: number, pw: number) => void;
  isFitToWidth: boolean;
  setZoomDirect: (value: number) => void;
}

export function useZoom(
  containerWidth: number,
  pageWidth: number,
  onZoomChange: (from: number, to: number) => void
): UseZoomResult {
  const [zoom, setZoom] = useState(1.0);
  const [isFitToWidth, setIsFitToWidth] = useState(false);

  const setZoomSafe = useCallback(
    (next: number) => {
      const clamped = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, Math.round(next * 100) / 100));
      setZoom((prev) => {
        onZoomChange(prev, clamped);
        return clamped;
      });
      setIsFitToWidth(false);
    },
    [onZoomChange]
  );

  const zoomIn = useCallback(() => setZoomSafe(zoom + STEP), [zoom, setZoomSafe]);
  const zoomOut = useCallback(() => setZoomSafe(zoom - STEP), [zoom, setZoomSafe]);

  const fitToWidth = useCallback(() => {
    if (pageWidth === 0 || containerWidth === 0) return;
    const fit = containerWidth / pageWidth;
    const clamped = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, fit));
    setZoom((prev) => {
      onZoomChange(prev, clamped);
      return clamped;
    });
    setIsFitToWidth(true);
  }, [containerWidth, pageWidth, onZoomChange]);

  const fitToWidthImmediate = useCallback((cw: number, pw: number) => {
    if (pw === 0 || cw === 0) return;
    const clamped = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, cw / pw));
    setZoom((prev) => {
      onZoomChange(prev, clamped);
      return clamped;
    });
    setIsFitToWidth(true);
  }, [onZoomChange]);

  return { zoom, zoomIn, zoomOut, fitToWidth, fitToWidthImmediate, isFitToWidth, setZoomDirect: setZoomSafe };
}
