import { useState, useEffect } from 'react';
import type { PDFDocumentProxy } from 'pdfjs-dist';

export interface OutlineItem {
  title: string;
  pageNumber: number;
}

export function usePdfOutline(pdfDoc: PDFDocumentProxy | null): OutlineItem[] {
  const [outline, setOutline] = useState<OutlineItem[]>([]);

  useEffect(() => {
    if (!pdfDoc) { setOutline([]); return; }
    let cancelled = false;

    (async () => {
      try {
        const items = await pdfDoc.getOutline();
        if (!items || items.length === 0 || cancelled) return;

        const resolved: OutlineItem[] = [];
        for (const item of items) {
          if (!item.dest) continue;
          try {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            let dest: any = item.dest;
            if (typeof dest === 'string') dest = await pdfDoc.getDestination(dest);
            if (!Array.isArray(dest) || dest.length === 0) continue;
            const pageIndex = await pdfDoc.getPageIndex(dest[0]);
            if (!cancelled) resolved.push({ title: item.title, pageNumber: pageIndex + 1 });
          } catch { /* skip unresolvable destination */ }
        }
        if (!cancelled) setOutline(resolved);
      } catch { /* PDF has no outline */ }
    })();

    return () => { cancelled = true; };
  }, [pdfDoc]);

  return outline;
}
