import type { CSSProperties } from 'react';

interface Props {
  percentage: number;
  onAccept: () => void;
  onDecline: () => void;
}

export function ResumePrompt({ percentage, onAccept, onDecline }: Props) {
  return (
    <div style={overlay}>
      <div style={card}>
        <h3 style={title}>Resume Reading</h3>
        <p style={msg}>
          You were at <strong>{percentage}%</strong> through this book.
          Continue from where you left off?
        </p>
        <div style={actions}>
          <button style={{ ...btn, background: '#2980b9' }} onClick={onAccept}>
            Resume from {percentage}%
          </button>
          <button style={{ ...btn, background: 'rgba(255,255,255,0.12)' }} onClick={onDecline}>
            Start from beginning
          </button>
        </div>
      </div>
    </div>
  );
}

