import { useState, useRef, useCallback } from 'react';

export type TapSide = 'left' | 'right';

export interface SmartTapFeedback {
  side: TapSide;
  totalDeltaSec: number;
  key: number;
}

interface SmartTapAccum {
  side: TapSide;
  count: number;
  totalDeltaSec: number;
}

const COMMIT_DELAY_MS = 650;
const SECONDS_PER_TAP = 5;

/**
 * Accumulates rapid taps on left/right zones and calls onCommit once
 * the tap sequence ends (after COMMIT_DELAY_MS of inactivity).
 * Each tap adds SECONDS_PER_TAP to the accumulated delta.
 */
export function useSmartTap(
  onCommit: (deltaSec: number, side: TapSide, tapCount: number) => void,
) {
  const [feedback, setFeedback] = useState<SmartTapFeedback | null>(null);
  const accumRef  = useRef<SmartTapAccum | null>(null);
  const timerRef  = useRef<ReturnType<typeof setTimeout> | null>(null);
  const feedbackTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const feedbackKey   = useRef(0);

  const handleTap = useCallback((side: TapSide) => {
    const current = accumRef.current;

    if (current && current.side === side) {
      accumRef.current = {
        side,
        count: current.count + 1,
        totalDeltaSec: current.totalDeltaSec + SECONDS_PER_TAP,
      };
    } else {
      if (timerRef.current) clearTimeout(timerRef.current);
      accumRef.current = { side, count: 1, totalDeltaSec: SECONDS_PER_TAP };
    }

    const { totalDeltaSec } = accumRef.current;
    feedbackKey.current += 1;
    setFeedback({ side, totalDeltaSec, key: feedbackKey.current });

    if (timerRef.current) clearTimeout(timerRef.current);
    timerRef.current = setTimeout(() => {
      const committed = accumRef.current;
      if (committed) {
        onCommit(committed.totalDeltaSec, committed.side, committed.count);
        accumRef.current = null;
      }
      // Clear feedback after short display period
      if (feedbackTimer.current) clearTimeout(feedbackTimer.current);
      feedbackTimer.current = setTimeout(() => setFeedback(null), 700);
    }, COMMIT_DELAY_MS);
  }, [onCommit]);

  return { handleTap, feedback };
}
