import {
  useEffect,
  useRef,
  useState,
  useCallback,
  forwardRef,
  useImperativeHandle,
  type CSSProperties,
} from 'react';
import type { RendererContext } from '@content/player-core';
import { SunbirdEID, VideoInteractId, saveProgress, getProgress } from '@content/player-core';
import { useBreakpoint } from './hooks/useBreakpoint';
import { useSmartTap } from './hooks/useSmartTap';
import { VideoControls } from './components/VideoControls';
import { CenterOverlay } from './components/CenterOverlay';
import { SmartTapFeedback } from './components/SmartTapFeedback';
import { ResumePrompt } from './components/ResumePrompt';

export interface VideoRendererHandle {
  getCurrentPositionMs(): number;
  getDurationMs(): number;
  getCompletionState(): boolean;
  seekToMs(ms: number): void;
}

interface Props {
  context: RendererContext;
  onReady: () => void;
  onStart: () => void;
  onProgress: (progress: number, positionMs: number, durationMs: number) => void;
  onComplete: () => void;
  onError: (message: string) => void;
}

const SKIP_DELTA_SEC        = 5;   // bottom-bar skip buttons
const CENTER_SKIP_DELTA_SEC = 10;  // on-screen center overlay skip
const CONTROLS_HIDE_DELAY_MS = 3000;
const HEADER_HEIGHT = 52;

export const VideoRendererView = forwardRef<VideoRendererHandle, Props>(
  function VideoRendererView({ context, onReady, onStart, onProgress, onComplete, onError }, ref) {
    const theme = context.extra?.theme;
    const accent = theme?.primary ?? '#2980b9';
    const titleBg = theme?.toolbar ?? 'rgba(14,14,20,0.97)';

    const breakpoint = useBreakpoint();
    const isPhone = breakpoint === 'phone';
    const isMobile = breakpoint !== 'desktop';

    const videoRef     = useRef<HTMLVideoElement>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const hideTimer    = useRef<ReturnType<typeof setTimeout> | null>(null);

    // ── Playback state ──────────────────────────────────────────────────────
    const [isPlaying,    setIsPlaying]    = useState(false);
    const [currentTime,  setCurrentTime]  = useState(0);
    const [duration,     setDuration]     = useState(0);
    const [volume,       setVolume]       = useState(1);
    const [muted,        setMuted]        = useState(false);
    const [buffering,    setBuffering]    = useState(false);
    const [playbackRate, setPlaybackRate] = useState(1);
    const [isFullscreen, setIsFullscreen] = useState(false);

    // ── UI state ────────────────────────────────────────────────────────────
    const [controlsVisible, setControlsVisible] = useState(true);
    const [showResume,      setShowResume]      = useState(false);
    const [savedPosSec,     setSavedPosSec]     = useState<number | null>(null);
    const [started,         setStarted]         = useState(false);
    const [metadataLoaded,  setMetadataLoaded]  = useState(false);
    const [showEndScreen,   setShowEndScreen]   = useState(false);
    const [timeSpentSec,    setTimeSpentSec]    = useState(0);

    // Track whether video has been completed
    const completedRef    = useRef(false);
    const startedRef      = useRef(false);
    const sessionStartRef = useRef(Date.now());

    // ── Controls auto-hide ──────────────────────────────────────────────────

    const showControls = useCallback(() => {
      setControlsVisible(true);
      if (hideTimer.current) clearTimeout(hideTimer.current);
    }, []);

    const scheduleHide = useCallback((playing: boolean) => {
      if (hideTimer.current) clearTimeout(hideTimer.current);
      if (playing) {
        hideTimer.current = setTimeout(() => setControlsVisible(false), CONTROLS_HIDE_DELAY_MS);
      }
    }, []);

    const handleActivity = useCallback(() => {
      showControls();
      scheduleHide(isPlaying);
    }, [isPlaying, showControls, scheduleHide]);

    // ── Resume check ────────────────────────────────────────────────────────

    useEffect(() => {
      if (!metadataLoaded) return;
      (async () => {
        const record       = await getProgress(context.contentId);
        const resumeMode   = context.extra?.resume?.mode ?? 'off';
        const resumeEnabled = context.extra?.resume?.enabled ?? false;
        const startPos     = context.extra?.video?.startPosition ?? 0;

        if (resumeEnabled && record?.positionMs && record.positionMs > 2000) {
          const posSec = record.positionMs / 1000;
          if (resumeMode === 'auto') {
            const v = videoRef.current;
            if (v) v.currentTime = posSec;
            context.emit(SunbirdEID.INTERACT, {
              type: 'TOUCH', subtype: '', id: VideoInteractId.RESUME_ACCEPT,
              pageid: String(Math.round(posSec)),
            });
            onReady();
            return;
          }
          if (resumeMode === 'prompt') {
            setSavedPosSec(posSec);
            setShowResume(true);
            context.emit(SunbirdEID.INTERACT, {
              type: 'TOUCH', subtype: '', id: VideoInteractId.RESUME_PROMPT_SHOWN,
              pageid: String(Math.round(posSec)),
            });
            return;
          }
        }

        if (startPos > 0 && videoRef.current) {
          videoRef.current.currentTime = startPos;
        }
        onReady();
      })();
    }, [metadataLoaded]); // eslint-disable-line react-hooks/exhaustive-deps

    // ── Resume handlers ─────────────────────────────────────────────────────

    const handleResumeAccept = useCallback(() => {
      if (savedPosSec !== null && videoRef.current) {
        videoRef.current.currentTime = savedPosSec;
      }
      setShowResume(false);
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.RESUME_ACCEPT,
        pageid: String(Math.round(savedPosSec ?? 0)),
      });
      onReady();
    }, [savedPosSec, context, onReady]);

    const handleResumeDecline = useCallback(() => {
      if (videoRef.current) videoRef.current.currentTime = 0;
      setShowResume(false);
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.RESUME_DECLINE,
        pageid: '0',
      });
      onReady();
    }, [context, onReady]);

    // ── Playback controls ───────────────────────────────────────────────────

    const togglePlayPause = useCallback(() => {
      const v = videoRef.current;
      if (!v) return;
      if (v.paused) {
        v.play().catch(() => {});
      } else {
        v.pause();
      }
    }, []);

    const handleSeek = useCallback((timeSec: number) => {
      const v = videoRef.current;
      if (!v) return;
      const from = v.currentTime;
      v.currentTime = timeSec;
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.SEEK_SCRUB,
        pageid: String(Math.round(timeSec)),
        extra: { fromSec: Math.round(from), toSec: Math.round(timeSec) },
      });
    }, [context]);

    const handleSkipBack = useCallback(() => {
      const v = videoRef.current;
      if (!v) return;
      const newTime = Math.max(0, v.currentTime - SKIP_DELTA_SEC);
      v.currentTime = newTime;
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.SKIP_BACKWARD,
        pageid: String(Math.round(newTime)),
        extra: { deltaSec: SKIP_DELTA_SEC },
      });
    }, [context]);

    const handleSkipForward = useCallback(() => {
      const v = videoRef.current;
      if (!v) return;
      const newTime = Math.min(v.duration || 0, v.currentTime + SKIP_DELTA_SEC);
      v.currentTime = newTime;
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.SKIP_FORWARD,
        pageid: String(Math.round(newTime)),
        extra: { deltaSec: SKIP_DELTA_SEC },
      });
    }, [context]);

    // Center overlay skip handlers use 10s
    const handleCenterSkipBack = useCallback(() => {
      const v = videoRef.current;
      if (!v) return;
      const newTime = Math.max(0, v.currentTime - CENTER_SKIP_DELTA_SEC);
      v.currentTime = newTime;
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.SKIP_BACKWARD,
        pageid: String(Math.round(newTime)),
        extra: { deltaSec: CENTER_SKIP_DELTA_SEC, trigger: 'center_overlay' },
      });
    }, [context]);

    const handleCenterSkipForward = useCallback(() => {
      const v = videoRef.current;
      if (!v) return;
      const newTime = Math.min(v.duration || 0, v.currentTime + CENTER_SKIP_DELTA_SEC);
      v.currentTime = newTime;
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.SKIP_FORWARD,
        pageid: String(Math.round(newTime)),
        extra: { deltaSec: CENTER_SKIP_DELTA_SEC, trigger: 'center_overlay' },
      });
    }, [context]);

    const handleRestart = useCallback(() => {
      const v = videoRef.current;
      if (!v) return;
      v.currentTime = 0;
      v.play().catch(() => {});
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.RESTART, pageid: '0',
      });
    }, [context]);

    const handleVolumeChange = useCallback((vol: number) => {
      const v = videoRef.current;
      if (!v) return;
      v.volume = vol;
      if (vol > 0 && v.muted) v.muted = false;
    }, []);

    const handleMuteToggle = useCallback(() => {
      const v = videoRef.current;
      if (!v) return;
      v.muted = !v.muted;
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.MUTE_TOGGLE,
        pageid: String(Math.round(v.currentTime)),
        extra: { muted: v.muted },
      });
    }, [context]);

    const handleRateChange = useCallback((rate: number) => {
      const v = videoRef.current;
      if (!v) return;
      const from = v.playbackRate;
      v.playbackRate = rate;
      setPlaybackRate(rate);
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.RATE_CHANGE,
        pageid: String(Math.round(v.currentTime)),
        extra: { fromRate: from, toRate: rate },
      });
    }, [context]);

    const toggleFullscreen = useCallback(() => {
      const el = containerRef.current;
      if (!el) return;
      if (!document.fullscreenElement) {
        el.requestFullscreen().catch(() => {});
        context.emit(SunbirdEID.INTERACT, {
          type: 'TOUCH', subtype: '', id: VideoInteractId.FULLSCREEN_ENTER,
          pageid: String(Math.round(videoRef.current?.currentTime ?? 0)),
        });
      } else {
        document.exitFullscreen().catch(() => {});
        context.emit(SunbirdEID.INTERACT, {
          type: 'TOUCH', subtype: '', id: VideoInteractId.FULLSCREEN_EXIT,
          pageid: String(Math.round(videoRef.current?.currentTime ?? 0)),
        });
      }
    }, [context]);

    useEffect(() => {
      const handler = () => setIsFullscreen(!!document.fullscreenElement);
      document.addEventListener('fullscreenchange', handler);
      return () => document.removeEventListener('fullscreenchange', handler);
    }, []);

    // ── Smart tap ───────────────────────────────────────────────────────────

    const { handleTap, feedback: smartTapFeedback } = useSmartTap(
      useCallback((deltaSec, side, tapCount) => {
        const v = videoRef.current;
        if (!v) return;
        const direction = side === 'right' ? 1 : -1;
        const newTime = Math.max(0, Math.min(v.duration || 0, v.currentTime + direction * deltaSec));
        v.currentTime = newTime;
        context.emit(SunbirdEID.INTERACT, {
          type: 'TOUCH', subtype: '',
          id: side === 'right' ? VideoInteractId.SMART_TAP_FORWARD : VideoInteractId.SMART_TAP_BACKWARD,
          pageid: String(Math.round(newTime)),
          extra: { deltaSec, tapCount, side },
        });
      }, [context]),
    );

    // ── Video element event handlers ────────────────────────────────────────

    const handleLoadedMetadata = useCallback(() => {
      const v = videoRef.current;
      if (!v) return;
      setDuration(v.duration);
      setMetadataLoaded(true);
    }, []);

    const handleTimeUpdate = useCallback(() => {
      const v = videoRef.current;
      if (!v) return;
      setCurrentTime(v.currentTime);
      const pct = v.duration > 0 ? (v.currentTime / v.duration) * 100 : 0;
      onProgress(pct, v.currentTime * 1000, v.duration * 1000);
    }, [onProgress]);

    const handlePlay = useCallback(() => {
      setIsPlaying(true);
      scheduleHide(true);
      const v = videoRef.current;
      if (!v) return;
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.PLAY,
        pageid: String(Math.round(v.currentTime)),
        extra: { positionMs: Math.round(v.currentTime * 1000), durationMs: Math.round(v.duration * 1000) },
      });
      if (!startedRef.current) {
        startedRef.current = true;
        setStarted(true);
        onStart();
      }
    }, [context, onStart, scheduleHide]);

    const handlePause = useCallback(() => {
      setIsPlaying(false);
      showControls();
      const v = videoRef.current;
      if (!v) return;
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.PAUSE,
        pageid: String(Math.round(v.currentTime)),
        extra: { positionMs: Math.round(v.currentTime * 1000) },
      });
    }, [context, showControls]);

    const handleEnded = useCallback(() => {
      setIsPlaying(false);
      showControls();
      if (!completedRef.current) {
        completedRef.current = true;
        onComplete(); // fires player:complete for host app; PlayerShell skips its EndScreen because hasOwnEndScreen=true
      }
      setTimeSpentSec(Math.round((Date.now() - sessionStartRef.current) / 1000));
      setShowEndScreen(true);
    }, [onComplete, showControls]);

    // ── End-screen actions ──────────────────────────────────────────────────

    const handleEndScreenReplay = useCallback(() => {
      setShowEndScreen(false);
      setTimeSpentSec(0);
      completedRef.current = false;
      sessionStartRef.current = Date.now();
      const v = videoRef.current;
      if (!v) return;
      v.currentTime = 0;
      v.play().catch(() => {});
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.RESTART, pageid: '0',
      });
    }, [context]);

    const handleEndScreenExit = useCallback(() => {
      const posPageId = String(Math.round(videoRef.current?.currentTime ?? 0));
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.EXIT_BUTTON, pageid: posPageId,
      });
      context.emit(SunbirdEID.END, {
        positionMs:  Math.round((videoRef.current?.currentTime ?? 0) * 1000),
        durationMs:  Math.round((videoRef.current?.duration  ?? 0) * 1000),
        timeSpentSec,
        isCompleted: true,
      });
      context.onExitRequest?.();
    }, [context, timeSpentSec]);

    const handleWaiting = useCallback(() => {
      setBuffering(true);
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.BUFFER_START,
        pageid: String(Math.round(videoRef.current?.currentTime ?? 0)),
      });
    }, [context]);

    const handleCanPlay = useCallback(() => {
      if (buffering) {
        context.emit(SunbirdEID.INTERACT, {
          type: 'TOUCH', subtype: '', id: VideoInteractId.BUFFER_END,
          pageid: String(Math.round(videoRef.current?.currentTime ?? 0)),
        });
      }
      setBuffering(false);
    }, [buffering, context]);

    const handleVolumeChangeEvent = useCallback(() => {
      const v = videoRef.current;
      if (!v) return;
      setVolume(v.volume);
      setMuted(v.muted);
    }, []);

    const handleVideoError = useCallback(() => {
      const v = videoRef.current;
      const msg = v?.error?.message ?? 'Video failed to load';
      onError(msg);
    }, [onError]);

    // ── Keyboard controls ───────────────────────────────────────────────────

    useEffect(() => {
      const el = containerRef.current;
      if (!el) return;
      const handler = (e: KeyboardEvent) => {
        if (e.key === ' ' || e.key === 'Spacebar') {
          e.preventDefault();
          togglePlayPause();
          handleActivity();
        } else if (e.key === 'ArrowRight') {
          e.preventDefault();
          handleSkipForward();
          handleActivity();
        } else if (e.key === 'ArrowLeft') {
          e.preventDefault();
          handleSkipBack();
          handleActivity();
        } else if (e.key === 'f' || e.key === 'F') {
          toggleFullscreen();
        } else if (e.key === 'm' || e.key === 'M') {
          handleMuteToggle();
        }
      };
      el.addEventListener('keydown', handler);
      return () => el.removeEventListener('keydown', handler);
    }, [togglePlayPause, handleSkipForward, handleSkipBack, toggleFullscreen, handleMuteToggle, handleActivity]);

    // ── Video area tap handling (mobile) ────────────────────────────────────

    const handleVideoTap = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
      const el = e.currentTarget;
      const rect = el.getBoundingClientRect();
      const relX = (e.clientX - rect.left) / rect.width;

      if (relX < 0.3) {
        handleTap('left');
      } else if (relX > 0.7) {
        handleTap('right');
      } else {
        // Center: toggle controls
        setControlsVisible((v) => {
          if (!v) scheduleHide(isPlaying);
          return !v;
        });
      }
    }, [handleTap, scheduleHide, isPlaying]);

    // Desktop: click video to play/pause
    const handleDesktopClick = useCallback(() => {
      togglePlayPause();
      handleActivity();
    }, [togglePlayPause, handleActivity]);

    // ── Exit (back arrow + three-dot menu) ─────────────────────────────────
    // Back arrow / three-dot: CLOSE if user exits mid-video; END if already completed.
    // Note: when the video reaches the end and the VideoEndScreen shows, the exit
    // button there calls handleEndScreenExit instead (always emits END).

    const handleExit = useCallback(() => {
      const isCompleted = completedRef.current;
      const posPageId   = String(Math.round(videoRef.current?.currentTime ?? 0));
      const spentSec    = Math.round((Date.now() - sessionStartRef.current) / 1000);
      context.emit(SunbirdEID.INTERACT, {
        type: 'TOUCH', subtype: '', id: VideoInteractId.EXIT_BUTTON,
        pageid: posPageId,
      });
      context.emit(isCompleted ? SunbirdEID.END : SunbirdEID.CLOSE, {
        positionMs:  Math.round((videoRef.current?.currentTime ?? 0) * 1000),
        durationMs:  Math.round((videoRef.current?.duration  ?? 0) * 1000),
        timeSpentSec: spentSec,
        isCompleted,
      });
      context.onExitRequest?.();
    }, [context]);

    // ── Imperative handle ───────────────────────────────────────────────────

    useImperativeHandle(ref, () => ({
      getCurrentPositionMs: () => (videoRef.current?.currentTime ?? 0) * 1000,
      getDurationMs: () => (videoRef.current?.duration ?? 0) * 1000,
      getCompletionState: () => completedRef.current,
      seekToMs: (ms: number) => {
        if (videoRef.current) videoRef.current.currentTime = ms / 1000;
      },
    }));

    // ── Cleanup ─────────────────────────────────────────────────────────────

    useEffect(() => {
      return () => {
        if (hideTimer.current) clearTimeout(hideTimer.current);
      };
    }, []);

    // ── Render ──────────────────────────────────────────────────────────────

    // Center overlay is shown on ALL breakpoints when controls are visible
    const showCenterOverlay = controlsVisible && !showResume && metadataLoaded;

    return (
      <div
        ref={containerRef}
        style={wrapper(theme?.background)}
        tabIndex={0}
        onMouseMove={!isMobile ? handleActivity : undefined}
      >
        {/* Top header */}
        <div style={headerBar(titleBg)}>
          <button style={headerIconBtn} onClick={handleExit} aria-label="Go back">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
              <path d="M19 12H5M12 5l-7 7 7 7"
                stroke="currentColor" strokeWidth="2"
                strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </button>
          <div style={headerTitle}>{context.contentName ?? 'Video'}</div>
          {/* Three-dot menu — exit only for now */}
          <HeaderMenu onExit={handleExit} toolbarBg={titleBg} />
        </div>

        {/* Video area */}
        <div
          style={videoArea}
          onClick={isMobile ? handleVideoTap : handleDesktopClick}
        >
          <video
            ref={videoRef}
            style={videoEl}
            src={context.src}
            preload="metadata"
            playsInline
            onLoadedMetadata={handleLoadedMetadata}
            onTimeUpdate={handleTimeUpdate}
            onPlay={handlePlay}
            onPause={handlePause}
            onEnded={handleEnded}
            onWaiting={handleWaiting}
            onCanPlay={handleCanPlay}
            onVolumeChange={handleVolumeChangeEvent}
            onError={handleVideoError}
          />

          {/* Buffering spinner */}
          {buffering && (
            <div style={bufferOverlay}>
              <div style={bufferSpinner(accent)} />
            </div>
          )}

          {/* Smart tap feedback */}
          {smartTapFeedback && (
            <SmartTapFeedback
              side={smartTapFeedback.side}
              totalDeltaSec={smartTapFeedback.totalDeltaSec}
              tapKey={smartTapFeedback.key}
            />
          )}

          {/* Center overlay — play/pause + ±10s — shown on ALL breakpoints when controls visible */}
          {showCenterOverlay && (
            <CenterOverlay
              isPlaying={isPlaying}
              buffering={buffering}
              skipDeltaSec={CENTER_SKIP_DELTA_SEC}
              onPlayPause={togglePlayPause}
              onSkipBack={handleCenterSkipBack}
              onSkipForward={handleCenterSkipForward}
              theme={theme}
            />
          )}
        </div>

        {/* Controls bar */}
        {(!isMobile || controlsVisible) && (
          <VideoControls
            isPhone={isPhone}
            isPlaying={isPlaying}
            currentTime={currentTime}
            duration={duration}
            volume={volume}
            muted={muted}
            playbackRate={playbackRate}
            isFullscreen={isFullscreen}
            theme={theme}
            onPlayPause={togglePlayPause}
            onSeek={handleSeek}
            onSkipBack={handleSkipBack}
            onSkipForward={handleSkipForward}
            onVolumeChange={handleVolumeChange}
            onMuteToggle={handleMuteToggle}
            onPlaybackRateChange={handleRateChange}
            onFullscreen={toggleFullscreen}
            onRestart={handleRestart}
          />
        )}

        {/* Resume prompt */}
        {showResume && savedPosSec !== null && (
          <ResumePrompt
            savedPositionSec={savedPosSec}
            onAccept={handleResumeAccept}
            onDecline={handleResumeDecline}
            theme={theme}
          />
        )}

        {/* End screen — shown when video reaches the end */}
        {showEndScreen && (
          <VideoEndScreen
            userName={context.userName}
            timeSpentSec={timeSpentSec}
            duration={duration}
            accent={accent}
            toolbarBg={titleBg}
            onReplay={handleEndScreenReplay}
            onExit={handleEndScreenExit}
          />
        )}
      </div>
    );
  }
);

// ── Styles ─────────────────────────────────────────────────────────────────

const wrapper = (bg?: string): CSSProperties => ({
  position: 'relative',
  width: '100%',
  height: '100%',
  display: 'flex',
  flexDirection: 'column',
  background: bg ?? '#000',
  outline: 'none',
  overflow: 'hidden',
});

const headerBar = (bg: string): CSSProperties => ({
  height: HEADER_HEIGHT,
  flexShrink: 0,
  background: bg,
  backdropFilter: 'blur(8px)',
  display: 'flex',
  alignItems: 'center',
  padding: '0 4px',
  borderBottom: '1px solid rgba(255,255,255,0.06)',
  zIndex: 10,
});

const headerIconBtn: CSSProperties = {
  width: 40,
  height: 40,
  flexShrink: 0,
  border: 'none',
  borderRadius: 8,
  background: 'none',
  color: '#fff',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  cursor: 'pointer',
};

const headerTitle: CSSProperties = {
  flex: 1,
  textAlign: 'center',
  color: '#fff',
  fontSize: 15,
  fontWeight: 500,
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  padding: '0 8px',
};

const videoArea: CSSProperties = {
  flex: 1,
  position: 'relative',
  overflow: 'hidden',
  background: '#000',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  cursor: 'pointer',
};

const videoEl: CSSProperties = {
  width: '100%',
  height: '100%',
  objectFit: 'contain',
  display: 'block',
};

const bufferOverlay: CSSProperties = {
  position: 'absolute',
  inset: 0,
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  background: 'rgba(0,0,0,0.3)',
  pointerEvents: 'none',
};

