import { useReducer, useEffect, useRef, useCallback, useState, type CSSProperties } from 'react';
import type { PlayerInitConfig, RendererInterface, RendererContext } from '@content/player-core';
import { TelemetryService, NoOpTransport, SunbirdEID } from '@content/player-core';
import { ErrorUI } from './components/ErrorUI';
import { EndScreen } from './components/EndScreen';

// ── Lifecycle state machine ────────────────────────────────────────────────

type Lifecycle = 'idle' | 'loading' | 'ready' | 'started' | 'progressing' | 'completed' | 'error' | 'closed';

interface ShellState {
  lifecycle: Lifecycle;
  errorMessage?: string;
  progress: number;
  timeSpentMs: number;
  lastPage?: number;
  totalPages?: number;
  visitedPages?: number;
  score?: number;
  maxScore?: number;
}

type ShellAction =
  | { type: 'LOAD' }
  | { type: 'READY' }
  | { type: 'START' }
  | { type: 'PROGRESS'; progress: number; lastPage?: number; totalPages?: number; visitedPages?: number }
  | { type: 'COMPLETE' }
  | { type: 'ERROR'; message: string }
  | { type: 'CLOSE' }
  | { type: 'REPLAY' }
  | { type: 'TICK'; timeSpentMs: number };

function reducer(state: ShellState, action: ShellAction): ShellState {
  switch (action.type) {
    case 'LOAD':     return { ...state, lifecycle: 'loading' };
    case 'READY':    return { ...state, lifecycle: 'ready' };
    case 'START':    return { ...state, lifecycle: 'started' };
    case 'PROGRESS': return {
      ...state,
      lifecycle: 'progressing',
      progress: action.progress,
      lastPage: action.lastPage,
      totalPages: action.totalPages,
      visitedPages: action.visitedPages,
    };
    case 'COMPLETE': return { ...state, lifecycle: 'completed' };
    case 'ERROR':    return { ...state, lifecycle: 'error', errorMessage: action.message };
    case 'CLOSE':    return { ...state, lifecycle: 'closed' };
    case 'REPLAY':   return { lifecycle: 'idle', progress: 0, timeSpentMs: 0 };
    case 'TICK':     return { ...state, timeSpentMs: action.timeSpentMs };
    default:         return state;
  }
}

// ── Component ──────────────────────────────────────────────────────────────

export interface PlayerShellProps {
  config: PlayerInitConfig;
  renderer: RendererInterface;
  onEvent?: (event: string, detail: unknown) => void;
}

export function PlayerShell({ config, renderer, onEvent }: PlayerShellProps) {
  const containerRef    = useRef<HTMLDivElement>(null);
  const sessionStartRef = useRef(Date.now());
  const readyTsRef      = useRef(0);
  const telemetryRef    = useRef<TelemetryService | null>(null);
  const sessionIdRef    = useRef('');
  const tickRef         = useRef<ReturnType<typeof setInterval> | null>(null);
  const endScreenShownRef   = useRef(false);
  // Prevents END telemetry from firing twice when content auto-completes then
  // user also clicks exit (e.g. PDF last page → end screen → exit button).
  const endTelemetryFiredRef = useRef(false);

  const [state, dispatch] = useReducer(reducer, {
    lifecycle: 'idle',
    progress: 0,
    timeSpentMs: 0,
  });

  // Keep a stable ref to latest state for use inside callbacks
  const stateRef = useRef(state);
  stateRef.current = state;

  // ── Bug 3 fix: replayKey drives re-mount of the renderer effect ──────────
  const [replayKey, setReplayKey] = useState(0);

  const emit = useCallback(
    (event: string, detail: unknown) => onEvent?.(event, detail),
    [onEvent]
  );

  // ── Bug 1 fix: stop tick timer when end screen is visible ────────────────
  useEffect(() => {
    if (state.lifecycle === 'completed' || state.lifecycle === 'closed') {
      if (tickRef.current) {
        clearInterval(tickRef.current);
        tickRef.current = null;
      }
    }
  }, [state.lifecycle]);

  // ── Main renderer lifecycle effect ───────────────────────────────────────
  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => {
    if (!containerRef.current) return;

    // Reset per-replay state
    sessionStartRef.current     = Date.now();
    endScreenShownRef.current   = false;
    endTelemetryFiredRef.current = false;

    // Clear stale handlers from the previous mount (fixes duplicate events on replay)
    renderer.removeAllListeners();

    // ── Bootstrap telemetry ──────────────────────────────────────────────
    const tConfig = config.telemetryConfig;
    const transport = tConfig.endpoint
      ? undefined // HttpTransport wired here in production
      : new NoOpTransport();
    const telemetry = new TelemetryService(tConfig, transport ?? new NoOpTransport(), (event) => {
      onEvent?.('playerTelemetryEvent', event);
    });
    telemetryRef.current = telemetry;

    const playSessionId = telemetry.startSession({
      contentId:     config.contentId,
      mimeType:      config.mimeType,
      mode:          config.mode,
      uid:           tConfig.uid,
      did:           tConfig.did,
      sid:           tConfig.sid,
      channel:       tConfig.channel,
      pdata:         tConfig.pdata,
      rollup:        tConfig.rollup,
      objectRollup:  tConfig.objectRollup,
      tags:          tConfig.tags,
      playerVersion: tConfig.playerVersion ?? '2.0',
      env:           tConfig.env ?? 'contentplayer',
      contentType:   config.metadata.contentType as string | undefined,
      contentVer:    String(config.metadata.pkgVersion ?? '1'),
      objectType:    'Content',
    });
    sessionIdRef.current = playSessionId;

    // ── Renderer event callbacks ─────────────────────────────────────────

    renderer.on('player:ready', () => {
      const loadTimeMs = Date.now() - sessionStartRef.current;
      readyTsRef.current = Date.now();

      telemetry.emit(
        SunbirdEID.START,
        {
          type:     'content',
          mode:     'play',
          pageid:   '',
          duration: parseFloat((loadTimeMs / 1000).toFixed(2)),
        },
        playSessionId,
        config.contentId
      );

      dispatch({ type: 'READY' });
      emit('player:ready', { contentId: config.contentId });
    });

    renderer.on('player:start', () => {
      dispatch({ type: 'START' });
      emit('player:start', { contentId: config.contentId });
    });

    renderer.on('player:progress', (payload) => {
      const p = payload as {
        progress: number;
        lastPage?: number;
        totalPages?: number;
        visitedPages?: number;
      };
      dispatch({
        type: 'PROGRESS',
        progress: p.progress,
        lastPage: p.lastPage,
        totalPages: p.totalPages,
        visitedPages: p.visitedPages,
      });
      emit('player:progress', p);
    });

    renderer.on('player:complete', () => {
      // Fire END telemetry immediately when content is fully consumed —
      // not only on exit — so the event is recorded even if the user
      // closes the browser tab after completing without clicking Exit.
      if (!endTelemetryFiredRef.current) {
        endTelemetryFiredRef.current = true;
        const s = stateRef.current;
        const completedTimeMs = Date.now() - sessionStartRef.current;
        telemetry.emit(
          SunbirdEID.END,
          {
            type:   'content',
            mode:   'play',
            pageid: 'content-completed',
            summary: [
              { progress:          100 },
              { totallength:       s.totalPages ?? 0 },
              { visitedlength:     s.totalPages ?? s.visitedPages ?? 0 },
              { visitedcontentend: true },
              { totalseekedlength: 0 },
              { endpageseen:       false },
            ],
            duration: parseFloat((completedTimeMs / 1000).toFixed(2)),
          },
          playSessionId,
          config.contentId,
          {
            identifier:  config.contentId,
            contentType: mimeToContentType(config.mimeType),
          }
        );
      }

      if (config.endScreenConfig.autoCloseOnComplete) {
        triggerClose('auto-complete', true);
      } else {
        dispatch({ type: 'COMPLETE' });
        emit('player:complete', { contentId: config.contentId });
      }
    });

    renderer.on('player:error', (payload) => {
      const p = payload as { message: string };
      telemetry.emit(
        SunbirdEID.ERROR,
        { err: p?.message ?? 'Unknown error', errtype: 'CONTENT', stacktrace: '' },
        playSessionId,
        config.contentId
      );
      dispatch({ type: 'ERROR', message: p?.message ?? 'Playback error' });
      emit('player:error', p);
    });

    // Tick timer — stopped by the Bug-1 effect when end screen shows
    tickRef.current = setInterval(() => {
      dispatch({ type: 'TICK', timeSpentMs: Date.now() - sessionStartRef.current });
    }, 1000);

    // ── Mount renderer ───────────────────────────────────────────────────
    const context: RendererContext = {
      contentId:    config.contentId,
      playSessionId,
      mimeType:     config.mimeType,
      src:          config.src,
      mode:         config.mode,
      extra:        config.extra,
      contentName:  config.metadata.name as string | undefined,
      userName:     config.userName,
      onExitRequest: () => triggerClose('user-exit'),
      emit: (eid, edata) =>
        telemetry.emit(eid, edata, playSessionId, config.contentId),
    };

    dispatch({ type: 'LOAD' });
    renderer.mount(containerRef.current, context).catch((err: Error) => {
      dispatch({ type: 'ERROR', message: err.message });
    });

    return () => {
      if (tickRef.current) { clearInterval(tickRef.current); tickRef.current = null; }
      telemetry.endSession(playSessionId);
      telemetry.destroy();
      renderer.unmount();
    };
  }, [replayKey]); // re-runs on replay — intentionally omitting other deps

  // ── Close / END helper ─────────────────────────────────────────────────

  function triggerClose(exitReason: string, fromAutoComplete = false) {
    void fromAutoComplete; // used for future feature flags
    const s = stateRef.current;
    const timeSpentMs = Date.now() - sessionStartRef.current;
    const telemetry = telemetryRef.current;
    const sid = sessionIdRef.current;

    // Only fire END telemetry if not already fired on content-complete.
    // This prevents double-counting when the user exits after the end screen.
    if (telemetry && !endTelemetryFiredRef.current) {
      endTelemetryFiredRef.current = true;
      const totalPages  = s.totalPages ?? 0;
      const visitedLen  = s.visitedPages ?? (s.lastPage ?? 0);
      const reachedEnd  = s.progress >= 100 || visitedLen === totalPages;
      const endPageSeen = endScreenShownRef.current;

      telemetry.emit(
        SunbirdEID.END,
        {
          type:   'content',
          mode:   'play',
          pageid: endPageSeen ? 'sunbird-player-Endpage' : String(s.lastPage ?? ''),
          summary: [
            { progress:            Math.round(s.progress) },
            { totallength:         totalPages },
            { visitedlength:       visitedLen },
            { visitedcontentend:   reachedEnd },
            { totalseekedlength:   0 },
            { endpageseen:         endPageSeen },
          ],
          duration: parseFloat((timeSpentMs / 1000).toFixed(2)),
        },
        sid,
        config.contentId,
        {
          identifier:  config.contentId,
          contentType: mimeToContentType(config.mimeType),
        }
      );
    }

    emit('player:close', { exitReason, timeSpentMs });
    dispatch({ type: 'CLOSE' });
  }

  const onExit = () => {
    const telemetry = telemetryRef.current;
    if (telemetry) {
      telemetry.emit(
        SunbirdEID.INTERACT,
        { type: 'TOUCH', subtype: '', id: 'exit_button', pageid: String(stateRef.current.lastPage ?? '') },
        sessionIdRef.current,
        config.contentId
      );
    }
    triggerClose('user-exit');
  };

  // ── Bug 3 fix: replay remounts the renderer via replayKey ────────────────
  const onReplay = () => {
    dispatch({ type: 'REPLAY' });
    setReplayKey((k) => k + 1);
  };

  // Track end screen shown
  if (state.lifecycle === 'completed' && !endScreenShownRef.current) {
    endScreenShownRef.current = true;
  }

  return (
    <div style={shell}>
      <style>{spinnerKeyframes}</style>
      <div ref={containerRef} style={contentArea} />

      {state.lifecycle === 'error' && (
        <ErrorUI
          message={state.errorMessage ?? 'An error occurred'}
          onClose={onExit}
        />
      )}

      {state.lifecycle === 'completed' && config.endScreenEnabled && !renderer.hasOwnEndScreen && (
        <EndScreen
          config={config.endScreenConfig}
          timeSpentMs={state.timeSpentMs}
          progress={state.progress}
          lastPage={state.lastPage}
          totalPages={state.totalPages}
          score={state.score}
          maxScore={state.maxScore}
          userName={config.userName}
          onExit={onExit}
          onReplay={config.endScreenConfig.showReplay ? onReplay : undefined}
        />
      )}
    </div>
  );
}

// ── Helpers ────────────────────────────────────────────────────────────────

function mimeToContentType(mimeType: string): string {
  if (mimeType === 'application/pdf') return 'pdf';
  if (mimeType.startsWith('video/')) return 'video';
  if (mimeType === 'application/epub') return 'epub';
  return mimeType.split('/').pop() ?? 'content';
}

const shell: CSSProperties = {
  position: 'relative',
  width: '100%',
  height: '100%',
  background: '#000',
  overflow: 'hidden',
};

const contentArea: CSSProperties = {
  width: '100%',
  height: '100%',
};

const spinnerKeyframes = `
  @keyframes spin { to { transform: rotate(360deg); } }
  @keyframes floatUp {
    0%, 100% { transform: translateY(0px); }
    50%       { transform: translateY(-10px); }
  }
`;
