import { useState, type CSSProperties, type ReactNode } from 'react';
import type { ThemeConfig } from '@content/player-core';

interface Props {
  currentPage: number;
  totalPages: number;
  zoom: number;
  isFitToWidth: boolean;
  /** True when on the last page — next button shows end-screen hint */
  isLastPage: boolean;
  isFullscreen: boolean;
  /** Phone gets a compact bar; tablet + desktop get the full bar with slider */
  isPhone: boolean;
  onPrev: () => void;
  onNext: () => void;
  onJumpTo: (page: number) => void;
  onZoomIn: () => void;
  onZoomOut: () => void;
  onFitToWidth: () => void;
  onToggleFullscreen: () => void;
  theme?: ThemeConfig;
}

export function Toolbar({
  currentPage,
  totalPages,
  zoom,
  isFitToWidth,
  isLastPage,
  isFullscreen,
  isPhone,
  onPrev,
  onNext,
  onJumpTo,
  onZoomIn,
  onZoomOut,
  onFitToWidth,
  onToggleFullscreen,
  theme,
}: Props) {
  const [editingPage, setEditingPage] = useState(false);
  const [pageInput, setPageInput] = useState('');

  const accent = theme?.primary;
  const barBg = theme?.toolbar ?? 'rgba(20,20,30,0.97)';
  const progress = totalPages > 0 ? Math.round((currentPage / totalPages) * 100) : 0;

  const commitJump = () => {
    const n = parseInt(pageInput, 10);
    if (!isNaN(n)) onJumpTo(n);
    setEditingPage(false);
    setPageInput('');
  };

  if (isPhone) {
    return (
      <div style={{ ...bar, background: barBg }}>
        {/* Navigation */}
        <div style={group}>
          <ToolBtn onClick={onPrev} disabled={currentPage <= 1} title="Previous page">‹</ToolBtn>
          <span
            style={mobilePageDisplay}
            onClick={() => { setEditingPage(true); setPageInput(String(currentPage)); }}
            title="Tap to jump to page"
          >
            {editingPage ? (
              <input
                autoFocus
                style={mobilePageInput}
                value={pageInput}
                onChange={e => setPageInput(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter') commitJump(); if (e.key === 'Escape') setEditingPage(false); }}
                onBlur={commitJump}
                type="number"
                min={1}
                max={totalPages}
              />
            ) : (
              `${currentPage} / ${totalPages}`
            )}
          </span>
          <ToolBtn
            onClick={onNext}
            title={isLastPage ? 'Show end screen' : 'Next page'}
            active={isLastPage}
            accent={accent}
          >›</ToolBtn>
        </div>

        {/* Zoom */}
        <div style={group}>
          <ToolBtn onClick={onZoomOut} disabled={zoom <= 0.5} title="Zoom out">−</ToolBtn>
          <ToolBtn
            onClick={onFitToWidth}
            title="Fit to page"
            active={isFitToWidth}
            accent={accent}
          >
            <FitToWidthIcon />
          </ToolBtn>
          <ToolBtn onClick={onZoomIn} disabled={zoom >= 3.0} title="Zoom in">+</ToolBtn>
        </div>
      </div>
    );
  }

  // ── Tablet + Desktop — full bar ──────────────────────────────────────────────
  return (
    <>
      {/* Slider thumb accent colour override */}
      <style>{sliderCss(accent ?? '#1a73e8')}</style>

      <div style={{ ...bar, background: barBg }}>
        {/* Navigation */}
        <div style={group}>
          <ToolBtn onClick={onPrev} disabled={currentPage <= 1} title="Previous page (←)">
            ← Previous
          </ToolBtn>

          <div style={pageIndicator}>
            <span style={pageLabelStyle}>Page</span>
            {editingPage ? (
              <input
                autoFocus
                style={pageInputStyle}
                value={pageInput}
                onChange={e => setPageInput(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter') commitJump(); if (e.key === 'Escape') setEditingPage(false); }}
                onBlur={commitJump}
                type="number"
                min={1}
                max={totalPages}
              />
            ) : (
              <span
                style={pageNumStyle}
                onClick={() => { setEditingPage(true); setPageInput(String(currentPage)); }}
                title="Click to jump to page"
              >
                {currentPage}
              </span>
            )}
            <span style={pageLabelStyle}>of {totalPages}</span>
          </div>

          <ToolBtn
            onClick={onNext}
            title={isLastPage ? 'Show end screen' : 'Next page (→)'}
            active={isLastPage}
            accent={accent}
          >
            Next →
          </ToolBtn>
        </div>

        {/* Progress slider */}
        <div style={group}>
          <ToolBtn onClick={onPrev} disabled={currentPage <= 1} title="Previous page">−</ToolBtn>
          <input
            type="range"
            className="pdf-progress-slider"
            min={1}
            max={totalPages || 1}
            value={currentPage}
            onChange={e => onJumpTo(parseInt(e.target.value, 10))}
            style={sliderStyle}
            aria-label="Reading progress"
          />
          <ToolBtn onClick={onNext} title="Next page">+</ToolBtn>
          <span style={progressLabelStyle}>{progress}%</span>
        </div>

        {/* Zoom */}
        <div style={group}>
          <ToolBtn onClick={onZoomOut} disabled={zoom <= 0.5} title="Zoom out">
            <ZoomOutIcon />
          </ToolBtn>
          <ToolBtn
            onClick={onFitToWidth}
            title="Fit to width"
            active={isFitToWidth}
            accent={accent}
            wide
          >
            {Math.round(zoom * 100)}%
          </ToolBtn>
          <ToolBtn onClick={onZoomIn} disabled={zoom >= 3.0} title="Zoom in">
            <ZoomInIcon />
          </ToolBtn>
          <ToolBtn
            onClick={onToggleFullscreen}
            title={isFullscreen ? 'Exit fullscreen' : 'Fullscreen'}
            active={isFullscreen}
            accent={accent}
          >
            {isFullscreen ? <CollapseIcon /> : <ExpandIcon />}
          </ToolBtn>
        </div>
      </div>
    </>
  );
}

// ── Sub-components ────────────────────────────────────────────────────────────

function ToolBtn({
  children,
  onClick,
  disabled,
  title,
  active,
  accent,
  wide,
}: {
  children: ReactNode;
  onClick: () => void;
  disabled?: boolean;
  title?: string;
  active?: boolean;
  accent?: string;
  wide?: boolean;
}) {
  return (
    <button
      style={{
        ...toolBtnBase,
        minWidth: wide ? 52 : 32,
        opacity: disabled ? 0.35 : 1,
        background: active
          ? (accent ?? 'rgba(255,255,255,0.28)')
          : 'rgba(255,255,255,0.08)',
        cursor: disabled ? 'default' : 'pointer',
      }}
      onClick={onClick}
      disabled={disabled}
      title={title}
    >
      {children}
    </button>
  );
}

function ZoomOutIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
      <circle cx="11" cy="11" r="7" stroke="currentColor" strokeWidth="2"/>
      <line x1="8" y1="11" x2="14" y2="11" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
      <line x1="16.5" y1="16.5" x2="21" y2="21" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
    </svg>
  );
}

function ZoomInIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
      <circle cx="11" cy="11" r="7" stroke="currentColor" strokeWidth="2"/>
      <line x1="8" y1="11" x2="14" y2="11" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
      <line x1="11" y1="8" x2="11" y2="14" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
      <line x1="16.5" y1="16.5" x2="21" y2="21" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
    </svg>
  );
}

function ExpandIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
      <path d="M8 3H5a2 2 0 0 0-2 2v3M21 8V5a2 2 0 0 0-2-2h-3M3 16v3a2 2 0 0 0 2 2h3M16 21h3a2 2 0 0 0 2-2v-3"
        stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
    </svg>
  );
}

function CollapseIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
      <path d="M8 3v3a2 2 0 0 1-2 2H3M21 8h-3a2 2 0 0 1-2-2V3M3 16h3a2 2 0 0 1 2 2v3M16 21v-3a2 2 0 0 1 2-2h3"
        stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
    </svg>
  );
}

function FitToWidthIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
      <path d="M3 9V5a2 2 0 0 1 2-2h4M15 3h4a2 2 0 0 1 2 2v4M21 15v4a2 2 0 0 1-2 2h-4M9 21H5a2 2 0 0 1-2-2v-4"
        stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
      <rect x="7" y="7" width="10" height="10" rx="1"
        stroke="currentColor" strokeWidth="2"/>
    </svg>
  );
}

// ── CSS for slider thumb (can't be done with inline styles) ───────────────────

const sliderCss = (accent: string) => `
  .pdf-progress-slider { -webkit-appearance: none; appearance: none; outline: none; }
  .pdf-progress-slider::-webkit-slider-thumb {
    -webkit-appearance: none; appearance: none;
    width: 13px; height: 13px; border-radius: 50%;
    background: ${accent}; cursor: pointer;
  }
  .pdf-progress-slider::-moz-range-thumb {
    width: 13px; height: 13px; border-radius: 50%;
    background: ${accent}; cursor: pointer; border: none;
  }
`;

