import { openDB, type IDBPDatabase } from 'idb';
import type { ProgressRecord, AttemptState } from '../types';

const DB_NAME = 'content-player-db';
const DB_VERSION = 1;

let _db: Promise<IDBPDatabase> | null = null;

function db(): Promise<IDBPDatabase> {
  if (!_db) {
    _db = openDB(DB_NAME, DB_VERSION, {
      upgrade(database) {
        if (!database.objectStoreNames.contains('progress')) {
          database.createObjectStore('progress', { keyPath: 'contentId' });
        }
        if (!database.objectStoreNames.contains('attemptState')) {
          database.createObjectStore('attemptState', { keyPath: 'contentId' });
        }
      },
    });
  }
  return _db;
}

export async function saveProgress(
  contentId: string,
  position: Partial<Omit<ProgressRecord, 'contentId' | 'updatedAt'>>
): Promise<void> {
  const store = await db();
  const existing = (await store.get('progress', contentId)) as ProgressRecord | undefined;
  const record: ProgressRecord = {
    ...existing,
    contentId,
    ...position,
    updatedAt: Date.now(),
  };
  await store.put('progress', record);
}

export async function getProgress(contentId: string): Promise<ProgressRecord | null> {
  const store = await db();
  return ((await store.get('progress', contentId)) as ProgressRecord | undefined) ?? null;
}

export async function clearProgress(contentId: string): Promise<void> {
  const store = await db();
  await store.delete('progress', contentId);
}

export async function saveAttemptState(
  contentId: string,
  state: Omit<AttemptState, 'contentId'>
): Promise<void> {
  const store = await db();
  await store.put('attemptState', { contentId, ...state });
}

export async function getAttemptState(contentId: string): Promise<AttemptState | null> {
  const store = await db();
  return ((await store.get('attemptState', contentId)) as AttemptState | undefined) ?? null;
}
