import type { CSSProperties } from 'react';
import type { ThemeConfig } from '@content/player-core';

interface Props {
  savedPositionSec: number;
  onAccept: () => void;
  onDecline: () => void;
  theme?: ThemeConfig;
}

function formatTime(sec: number): string {
  const m = Math.floor(sec / 60);
  const s = Math.floor(sec % 60);
  return `${m}:${s.toString().padStart(2, '0')}`;
}

export function ResumePrompt({ savedPositionSec, onAccept, onDecline, theme }: Props) {
  const accent = theme?.primary ?? '#2980b9';

  return (
    <div style={overlay}>
      <div style={dialog}>
        <div style={iconWrap}>
          <svg width="32" height="32" viewBox="0 0 24 24" fill="none">
            <circle cx="12" cy="12" r="10" stroke={accent} strokeWidth="2" />
            <path d="M12 7v5l3 3" stroke={accent} strokeWidth="2"
              strokeLinecap="round" strokeLinejoin="round" />
          </svg>
        </div>
        <div style={title}>Resume Video?</div>
        <div style={subtitle}>
          Continue from <strong style={{ color: accent }}>{formatTime(savedPositionSec)}</strong>
          {' '}where you left off?
        </div>
        <div style={btnRow}>
          <button style={{ ...btn, background: 'rgba(255,255,255,0.08)', color: '#ccc' }}
            onClick={onDecline}>
            Start Over
          </button>
          <button style={{ ...btn, background: accent, color: '#fff' }}
            onClick={onAccept}>
            Resume
          </button>
        </div>
      </div>
    </div>
  );
}

const overlay: CSSProperties = {
  position: 'absolute',
  inset: 0,
  background: 'rgba(0,0,0,0.72)',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  zIndex: 50,
};

const dialog: CSSProperties = {
  background: '#1e1e2e',
  borderRadius: 14,
  padding: '28px 32px',
  maxWidth: 320,
  width: '90%',
  textAlign: 'center',
  boxShadow: '0 24px 64px rgba(0,0,0,0.6)',
  border: '1px solid rgba(255,255,255,0.08)',
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
};

const iconWrap: CSSProperties = { marginBottom: 14 };

const title: CSSProperties = {
  color: '#fff',
  fontSize: 17,
  fontWeight: 700,
  marginBottom: 8,
};

const subtitle: CSSProperties = {
  color: 'rgba(255,255,255,0.65)',
  fontSize: 14,
  lineHeight: 1.5,
  marginBottom: 22,
};

const btnRow: CSSProperties = {
  display: 'flex',
  gap: 10,
};

const btn: CSSProperties = {
  flex: 1,
  padding: '10px 0',
  border: 'none',
  borderRadius: 8,
  cursor: 'pointer',
  fontSize: 14,
  fontWeight: 600,
  fontFamily: 'inherit',
  transition: 'opacity 0.15s',
};
