import type { TelemetryConfig } from '../types';

// ── Sunbird telemetry envelope ─────────────────────────────────────────────

export interface SunbirdTelemetryEvent {
  eid: string;
  ets: number;
  ver: '3.0';
  mid: string;
  actor: { id: string; type: 'User' };
  context: {
    channel: string;
    pdata: { id: string; ver: string; pid: string };
    env: string;
    sid: string;
    did: string;
    cdata: Array<{ id: string; type: string }>;
    rollup: Record<string, string>;
    uid: string;
  };
  object: {
    id: string;
    ver: string;
    type: string;
    rollup: Record<string, string>;
  };
  tags: string[];
  edata: Record<string, unknown>;
  [key: string]: unknown; // allows top-level extra fields (identifier, contentType on END)
}

export interface TelemetryTransport {
  send(events: SunbirdTelemetryEvent[]): Promise<void>;
}

// ── Session context (passed on startSession) ───────────────────────────────

export interface SessionContext {
  contentId: string;
  contentVer?: string;
  contentType?: string;
  objectType?: string;
  mimeType: string;
  mode: 'online' | 'offline';
  // Sunbird identity
  uid?: string;
  did?: string;
  sid?: string;
  channel?: string;
  pdata?: { id: string; ver: string; pid?: string };
  rollup?: Record<string, string>;
  objectRollup?: Record<string, string>;
  tags?: string[];
  playerVersion?: string;
  env?: string;
}

interface ActiveSession {
  context: SessionContext;
  contentSessionId: string;
  playSessionId: string;
}

// ── Helpers ────────────────────────────────────────────────────────────────

const PII_KEYS = new Set(['email', 'phone', 'password']);

function redactPii(payload: Record<string, unknown>): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(payload)) {
    if (!PII_KEYS.has(k.toLowerCase())) out[k] = v;
  }
  return out;
}

function randomHex(bytes = 16): string {
  const arr = new Uint8Array(bytes);
  if (typeof crypto !== 'undefined' && crypto.getRandomValues) {
    crypto.getRandomValues(arr);
  } else {
    for (let i = 0; i < bytes; i++) arr[i] = Math.floor(Math.random() * 256);
  }
  return Array.from(arr)
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
}

function generateMid(eid: string): string {
  return `${eid}:${randomHex(16)}`;
}

// ── TelemetryService ───────────────────────────────────────────────────────

export class TelemetryService {
  private queue: SunbirdTelemetryEvent[] = [];
  private flushTimer: ReturnType<typeof setInterval> | null = null;
  private sessions = new Map<string, ActiveSession>();

  constructor(
    private readonly config: TelemetryConfig,
    private readonly transport: TelemetryTransport,
    private readonly onEmit?: (event: SunbirdTelemetryEvent) => void
  ) {
    this.startFlushTimer();
  }

  /** Creates a play session and returns its playSessionId. */
  startSession(context: SessionContext): string {
    const playSessionId = randomHex(16);
    const contentSessionId = randomHex(16);
    this.sessions.set(playSessionId, { context, contentSessionId, playSessionId });
    return playSessionId;
  }

  endSession(playSessionId: string): void {
    this.sessions.delete(playSessionId);
  }

  /**
   * Emit a Sunbird telemetry event.
   *
   * @param eid        - Sunbird event ID: 'START' | 'INTERACT' | 'END' | 'ERROR' etc.
   * @param edata      - Event-specific data payload
   * @param sessionId  - playSessionId returned by startSession()
   * @param contentId  - content identifier
   * @param topLevel   - Optional extra fields merged at the envelope root (e.g. identifier, contentType on END)
   */
  emit(
    eid: string,
    edata: Record<string, unknown>,
    sessionId: string,
    contentId: string,
    topLevel?: Record<string, unknown>
  ): void {
    const session = this.sessions.get(sessionId);
    const envelope = this.buildEnvelope(eid, edata, session, contentId, topLevel);
    this.onEmit?.(envelope);
    this.queue.push(envelope);
  }

  async flush(): Promise<void> {
    if (this.queue.length === 0) return;
    const batch = this.queue.splice(0);
    let attempt = 0;
    while (attempt < 3) {
      try {
        await this.transport.send(batch);
        return;
      } catch {
        attempt++;
        if (attempt < 3) await new Promise((r) => setTimeout(r, 1000 * Math.pow(2, attempt)));
      }
    }
    // drop after max retries
  }

  destroy(): void {
    if (this.flushTimer) clearInterval(this.flushTimer);
    void this.flush();
  }

  // ── Private ────────────────────────────────────────────────────────────

  private buildEnvelope(
    eid: string,
    edata: Record<string, unknown>,
    session: ActiveSession | undefined,
    contentId: string,
    topLevel?: Record<string, unknown>
  ): SunbirdTelemetryEvent {
    const ctx = session?.context;

    const pdata = ctx?.pdata ?? this.config.pdata ?? { id: 'content-player', ver: '0.1.0', pid: '' };
    const uid = ctx?.uid ?? this.config.uid ?? '';
    const did = ctx?.did ?? this.config.did ?? '';
    const sid = ctx?.sid ?? this.config.sid ?? '';
    const channel = ctx?.channel ?? this.config.channel ?? '';
    const rollup = ctx?.rollup ?? this.config.rollup ?? {};
    const tags = ctx?.tags ?? this.config.tags ?? (channel ? [channel] : []);
    const playerVersion = ctx?.playerVersion ?? this.config.playerVersion ?? '2.0';
    const env = ctx?.env ?? this.config.env ?? 'contentplayer';

    const cdata: Array<{ id: string; type: string }> = [];
    if (session) {
      cdata.push({ id: session.contentSessionId, type: 'ContentSession' });
      cdata.push({ id: session.playSessionId, type: 'PlaySession' });
    }
    cdata.push({ id: playerVersion, type: 'PlayerVersion' });

    return {
      eid,
      ets: Date.now(),
      ver: '3.0',
      mid: generateMid(eid),
      actor: { id: uid, type: 'User' },
      context: {
        channel,
        pdata: { id: pdata.id, ver: pdata.ver, pid: pdata.pid ?? '' },
        env,
        sid,
        did,
        cdata,
        rollup,
        uid,
      },
      object: {
        id: contentId,
        ver: ctx?.contentVer ?? '1',
        type: ctx?.objectType ?? 'Content',
        rollup: ctx?.objectRollup ?? {},
      },
      tags,
      edata: redactPii(edata),
      ...topLevel,
    };
  }

  private startFlushTimer(): void {
    const interval = this.config.flushIntervalMs ?? 10_000;
    this.flushTimer = setInterval(() => void this.flush(), interval);
  }
}
