import { useState, useEffect } from 'react';
import type { PDFDocumentProxy } from 'pdfjs-dist';
import * as pdfjsLib from 'pdfjs-dist';

export interface UsePdfDocumentResult {
  pdfDoc: PDFDocumentProxy | null;
  totalPages: number;
  loading: boolean;
  loadingProgress: number; // 0–100
  error: string | null;
}

export interface UsePdfDocumentOptions {
  workerSrc?: string;
  cMapUrl?: string;
  standardFontDataUrl?: string;
}

export function usePdfDocument(src: string, options: UsePdfDocumentOptions = {}): UsePdfDocumentResult {
  const { workerSrc, cMapUrl, standardFontDataUrl } = options;

  const [pdfDoc, setPdfDoc] = useState<PDFDocumentProxy | null>(null);
  const [totalPages, setTotalPages] = useState(0);
  const [loading, setLoading] = useState(true);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!src) return;

    pdfjsLib.GlobalWorkerOptions.workerSrc =
      workerSrc ??
      `https://cdnjs.cloudflare.com/ajax/libs/pdf.js/${pdfjsLib.version}/pdf.worker.min.mjs`;

    const resolvedCMapUrl =
      cMapUrl ?? `https://unpkg.com/pdfjs-dist@${pdfjsLib.version}/cmaps/`;
    const resolvedStandardFontUrl =
      standardFontDataUrl ?? `https://unpkg.com/pdfjs-dist@${pdfjsLib.version}/standard_fonts/`;

    let cancelled = false;
    setLoading(true);
    setLoadingProgress(0);
    setError(null);

    const loadingTask = pdfjsLib.getDocument({
      url: src,
      cMapUrl: resolvedCMapUrl,
      cMapPacked: true,
      standardFontDataUrl: resolvedStandardFontUrl,
    });

    // Track download progress — some servers omit Content-Length so `total` may be 0
    loadingTask.onProgress = ({ loaded, total }: { loaded: number; total: number }) => {
      if (cancelled) return;
      if (total > 0) {
        setLoadingProgress(Math.min(99, Math.round((loaded / total) * 100)));
      } else {
        // Pulse forward when Content-Length is unknown
        setLoadingProgress((p) => Math.min(p + 3, 90));
      }
    };

    loadingTask.promise
      .then((doc) => {
        if (cancelled) return;
        setPdfDoc(doc);
        setTotalPages(doc.numPages);
        setLoadingProgress(100);
        setLoading(false);
      })
      .catch((err: Error) => {
        if (cancelled) return;
        setError(err.message ?? 'Failed to load PDF');
        setLoading(false);
      });

    return () => {
      cancelled = true;
      loadingTask.destroy();
    };
  }, [src, workerSrc, cMapUrl, standardFontDataUrl]);

  return { pdfDoc, totalPages, loading, loadingProgress, error };
}
