import type { CSSProperties } from 'react';
import type { EndScreenConfig } from '@content/player-core';

interface Props {
  config: EndScreenConfig;
  timeSpentMs: number;
  progress: number;
  lastPage?: number;
  totalPages?: number;
  score?: number;
  maxScore?: number;
  userName?: string;
  onExit: () => void;
  onReplay?: () => void;
}

function formatDuration(ms: number): string {
  const secs = Math.floor(ms / 1000);
  const m = Math.floor(secs / 60);
  const s = secs % 60;
  return `${m}m ${s}s`;
}

export function EndScreen({
  config,
  timeSpentMs,
  progress,
  lastPage,
  totalPages,
  score,
  maxScore,
  userName,
  onExit,
  onReplay,
}: Props) {
  const displayName = userName ?? 'Guest User';
  return (
    <div style={overlay}>
      <div style={card}>
        <div style={checkmark}>✓</div>
        <h2 style={title}>Content Complete</h2>
        <p style={completionMsg}>{displayName} completed the content</p>

        {config.showSessionSummary && (
          <div style={summary}>
            <div style={row}>
              <span style={label}>Time Spent</span>
              <span style={value}>{formatDuration(timeSpentMs)}</span>
            </div>
            <div style={row}>
              <span style={label}>Progress</span>
              <span style={value}>{Math.round(progress)}%</span>
            </div>
            {lastPage !== undefined && totalPages !== undefined && (
              <div style={row}>
                <span style={label}>Page</span>
                <span style={value}>
                  {lastPage} / {totalPages}
                </span>
              </div>
            )}
            {config.showScore && score !== undefined && maxScore !== undefined && (
              <div style={row}>
                <span style={label}>Score</span>
                <span style={value}>
                  {score} / {maxScore}
                </span>
              </div>
            )}
          </div>
        )}

        <div style={actions}>
          {config.showReplay && onReplay && (
            <button style={{ ...btn, background: '#2980b9' }} onClick={onReplay}>
              Replay
            </button>
          )}
          {config.exitLabel && (
            <button style={{ ...btn, background: '#27ae60' }} onClick={onExit}>
              {config.exitLabel}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

const overlay: CSSProperties = {
  position: 'absolute',
  inset: 0,
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  background: 'rgba(0,0,0,0.85)',
  zIndex: 30,
};

const card: CSSProperties = {
  background: '#1e1e2e',
  borderRadius: 16,
  padding: '40px 48px',
  textAlign: 'center',
  color: '#fff',
  minWidth: 320,
  maxWidth: 420,
  boxShadow: '0 8px 32px rgba(0,0,0,0.5)',
};

const checkmark: CSSProperties = {
  fontSize: 56,
  color: '#27ae60',
  marginBottom: 8,
};

const title: CSSProperties = {
  margin: '0 0 8px',
  fontSize: 22,
  fontWeight: 600,
};

const completionMsg: CSSProperties = {
  margin: '0 0 20px',
  fontSize: 14,
  color: 'rgba(255,255,255,0.65)',
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
};

const summary: CSSProperties = {
  background: 'rgba(255,255,255,0.05)',
  borderRadius: 8,
  padding: '12px 16px',
  marginBottom: 24,
};

const row: CSSProperties = {
  display: 'flex',
  justifyContent: 'space-between',
  padding: '6px 0',
  fontSize: 14,
  borderBottom: '1px solid rgba(255,255,255,0.08)',
};

const label: CSSProperties = { opacity: 0.6 };
const value: CSSProperties = { fontWeight: 600 };

const actions: CSSProperties = {
  display: 'flex',
  gap: 12,
  justifyContent: 'center',
};

const btn: CSSProperties = {
  padding: '10px 28px',
  border: 'none',
  borderRadius: 8,
  color: '#fff',
  cursor: 'pointer',
  fontSize: 15,
  fontWeight: 600,
};
