import type { CSSProperties } from 'react';
import type { TapSide } from '../hooks/useSmartTap';

interface Props {
  side: TapSide;
  totalDeltaSec: number;
  tapKey: number;
}

export function SmartTapFeedback({ side, totalDeltaSec, tapKey }: Props) {
  const label = side === 'right'
    ? `+${totalDeltaSec}s`
    : `−${totalDeltaSec}s`;

  return (
    <div key={tapKey} style={container(side)}>
      <div style={ripple} />
      <span style={labelStyle}>{label}</span>
      <div style={arrows(side)}>
        {side === 'right' ? '›' : '‹'}
      </div>
    </div>
  );
}

const container = (side: TapSide): CSSProperties => ({
  position: 'absolute',
  top: '50%',
  [side === 'right' ? 'right' : 'left']: '8%',
  transform: 'translateY(-50%)',
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  gap: 4,
  pointerEvents: 'none',
  animation: 'tapFadeIn 0.15s ease-out',
});

const ripple: CSSProperties = {
  position: 'absolute',
  width: 90,
  height: 90,
  borderRadius: '50%',
  background: 'rgba(255,255,255,0.12)',
  animation: 'tapRipple 0.5s ease-out forwards',
};

const labelStyle: CSSProperties = {
  color: '#fff',
  fontSize: 18,
  fontWeight: 700,
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
  textShadow: '0 2px 8px rgba(0,0,0,0.8)',
  zIndex: 1,
};

const arrows = (side: TapSide): CSSProperties => ({
  color: 'rgba(255,255,255,0.8)',
  fontSize: 28,
  lineHeight: 1,
  letterSpacing: side === 'right' ? 2 : -2,
  zIndex: 1,
});
