import { useEffect, useRef, forwardRef, useImperativeHandle } from 'react';
import type { PDFDocumentProxy, PDFPageProxy } from 'pdfjs-dist';

export interface PageCanvasHandle {
  pageWidth: number;
}

interface Props {
  pdfDoc: PDFDocumentProxy;
  pageNumber: number;
  zoom: number;
  onRendered?: () => void;
}

export const PageCanvas = forwardRef<PageCanvasHandle, Props>(function PageCanvas(
  { pdfDoc, pageNumber, zoom, onRendered },
  ref
) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const pageRef = useRef<PDFPageProxy | null>(null);
  const renderTaskRef = useRef<{ cancel: () => void } | null>(null);

  useImperativeHandle(ref, () => ({
    get pageWidth() {
      return pageRef.current?.getViewport({ scale: 1 }).width ?? 0;
    },
  }));

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || !pdfDoc) return;

    let cancelled = false;

    // Cancel any in-flight render
    renderTaskRef.current?.cancel();

    pdfDoc.getPage(pageNumber).then((page) => {
      if (cancelled) return;
      pageRef.current = page;

      const viewport = page.getViewport({ scale: zoom });
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      canvas.width = viewport.width;
      canvas.height = viewport.height;

      const renderTask = page.render({ canvasContext: ctx, viewport });
      renderTaskRef.current = renderTask;

      renderTask.promise
        .then(() => {
          if (!cancelled) onRendered?.();
        })
        .catch(() => {
          // render cancelled — no-op
        });
    });

    return () => {
      cancelled = true;
      renderTaskRef.current?.cancel();
    };
  }, [pdfDoc, pageNumber, zoom, onRendered]);

  return (
    <canvas
      ref={canvasRef}
      style={{ display: 'block', boxShadow: '0 2px 12px rgba(0,0,0,0.4)' }}
    />
  );
});
